def contrast_estimate(raster: Raster) -> dict[str, float]:
    source = raster.to_rgb()
    luminances: list[int] = []
    for index in range(0, len(source.data), 3):
        red = source.data[index]
        green = source.data[index + 1]
        blue = source.data[index + 2]
        luminances.append(int(0.299 * red + 0.587 * green + 0.114 * blue))
    if not luminances:
        return {"min": 0.0, "max": 0.0, "range": 0.0, "stddev": 0.0}
    mean = sum(luminances) / len(luminances)
    variance = sum((value - mean) ** 2 for value in luminances) / len(luminances)
    return {
        "min": float(min(luminances)),
        "max": float(max(luminances)),
        "range": float(max(luminances) - min(luminances)),
        "stddev": round(math.sqrt(variance), 3),
    }
